"use client"

import { useEffect, useState } from "react"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { LocalDB } from "@/lib/local-storage/db"

export function FundPositions({ fundId }: { fundId: string }) {
  const [positions, setPositions] = useState<any[]>([])

  useEffect(() => {
    let mounted = true
    const load = async () => {
      try {
        const all = await LocalDB.getAllInvestments()
        const filtered = (all || []).filter((p: any) => p.fund_id === fundId).map((p: any) => ({
          ...p,
          current_value: Number(p.current_value || 0),
        }))
        if (!mounted) return
        setPositions(filtered)
      } catch (err) {
        console.error(err)
      }
    }

    load()
    return () => {
      mounted = false
    }
  }, [fundId])

  const total = positions.reduce((s, p) => s + Number(p.current_value || 0), 0)

  return (
    <Card>
      <CardHeader>
        <CardTitle>Positions</CardTitle>
      </CardHeader>
      <CardContent>
        <div className="mb-3 text-sm text-gray-500">Total Position Value: ₹{total.toFixed(2)}</div>
        {positions.length === 0 && <div className="text-sm text-gray-500">No positions in this fund.</div>}
        <div className="space-y-2">
          {positions.map((p) => (
            <div key={p.id} className="flex items-center justify-between rounded-md border p-3">
              <div>
                <div className="text-sm font-medium">Investor: {p.investor_id}</div>
                <div className="text-xs text-gray-500">Units: {Number(p.units).toFixed(2)} — Avg NAV: ₹{Number(p.average_nav).toFixed(2)}</div>
              </div>
              <div className="text-right">
                <div className="font-semibold">₹{Number(p.current_value).toFixed(2)}</div>
              </div>
            </div>
          ))}
        </div>
      </CardContent>
    </Card>
  )
}
