"use client"

import { useEffect, useState } from "react"
import { useParams, useRouter } from "next/navigation"
import { useAuth } from "@/lib/auth-context"
import { DashboardHeader } from "@/components/dashboard-header"
import { LocalDB } from "@/lib/local-storage/db"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { PositionSizer } from "@/components/manager/position-sizer"
import { FundTransactions } from "@/components/manager/fund-transactions"
import { FundPositions } from "@/components/manager/fund-positions"

export default function FundDetailPage() {
  const { id } = useParams() as { id: string }
  const { user, loading } = useAuth()
  const router = useRouter()

  const [fund, setFund] = useState<any | null>(null)
  const [amount, setAmount] = useState<number>(0)
  const [orderType, setOrderType] = useState<'buy' | 'sell'>('buy')
  const [processing, setProcessing] = useState(false)
  const [units, setUnits] = useState<number>(0)

  useEffect(() => {
    if (!loading && !user) {
      router.push('/auth/login')
      return
    }

    if (user && user.role !== 'portfolio_manager') {
      router.push('/auth/login')
      return
    }

    if (user) loadFund()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user, loading, id])

  const loadFund = async () => {
    const f = await LocalDB.getFund(id)
    setFund(f)
  }

  const submitOrder = async () => {
    if (!fund || !user) return
    setProcessing(true)
    try {
      const nav = fund.nav || 1
      const orderUnits = units > 0 ? units : amount / nav
      // For demo, use createTransaction to record manager's action
      await LocalDB.createTransaction(user.id, fund.id, orderType, Number(amount), orderUnits, nav)
      // Optionally create investment record on buy
      if (orderType === 'buy') {
        await LocalDB.createInvestment(user.id, fund.id, Number(amount), nav)
      }
      await loadFund()
      alert('Order placed (demo)')
    } catch (err: any) {
      console.error(err)
      alert(err?.message || 'Order failed')
    } finally {
      setProcessing(false)
    }
  }

  if (loading || !user || !fund) {
    return (
      <div className="flex min-h-screen items-center justify-center">
        <div className="text-center">
          <div className="h-8 w-8 animate-spin rounded-full border-4 border-blue-600 border-t-transparent mx-auto mb-4"></div>
          <p className="text-gray-600">Loading fund...</p>
        </div>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <DashboardHeader user={user} />

      <main className="container mx-auto p-6">
        <div className="mb-6">
          <h1 className="text-3xl font-bold text-gray-900">{fund.fund_name}</h1>
          <p className="text-gray-600">{fund.objective}</p>
        </div>

        <div className="grid gap-6 md:grid-cols-3">
          <div className="md:col-span-1 rounded-lg border p-6">
            <h3 className="text-lg font-semibold mb-4">Fund Details</h3>
            <p><strong>Code:</strong> {fund.fund_code}</p>
            <p><strong>Type:</strong> {fund.fund_type}</p>
            <p><strong>Benchmark:</strong> {fund.benchmark}</p>
            <p><strong>NAV:</strong> ₹{Number(fund.nav).toFixed(2)}</p>
            <p><strong>AUM:</strong> ₹{Number(fund.aum).toLocaleString()}</p>
          </div>

          <div className="md:col-span-1 space-y-4">
            <PositionSizer fundAUM={Number(fund.aum || 0)} nav={Number(fund.nav || 1)} onSuggest={(amt, u) => { setAmount(Number(amt.toFixed(2))); setUnits(Number(u.toFixed(2))) }} />

            <div className="rounded-lg border p-6">
              <h3 className="text-lg font-semibold mb-4">Place Trade (Demo)</h3>
              <div className="mb-3">
                <label className="block text-sm text-gray-700 mb-1">Type</label>
                <div className="flex gap-2">
                  <button className={`px-3 py-1 rounded ${orderType === 'buy' ? 'bg-blue-600 text-white' : 'bg-gray-100'}`} onClick={() => setOrderType('buy')}>Buy</button>
                  <button className={`px-3 py-1 rounded ${orderType === 'sell' ? 'bg-blue-600 text-white' : 'bg-gray-100'}`} onClick={() => setOrderType('sell')}>Sell</button>
                </div>
              </div>

              <div className="mb-3">
                <label className="block text-sm text-gray-700 mb-1">Amount (INR)</label>
                <Input type="number" value={amount || ''} onChange={(e: any) => setAmount(Number(e.target.value))} />
              </div>

              <div className="mb-3">
                <label className="block text-sm text-gray-700 mb-1">Units</label>
                <Input type="number" value={units || ''} onChange={(e: any) => setUnits(Number(e.target.value))} />
              </div>

              <div className="mt-4">
                <Button onClick={submitOrder} disabled={processing || amount <= 0}>{processing ? 'Processing...' : 'Place Order (Demo)'}</Button>
              </div>
            </div>
          </div>

          <div className="md:col-span-1 space-y-4">
            <FundPositions fundId={fund.id} />
            <FundTransactions fundId={fund.id} />
          </div>
        </div>
      </main>
    </div>
  )
}
