"use client"

import { useEffect, useMemo, useState } from "react"
import { Input } from "@/components/ui/input"
import { Button } from "@/components/ui/button"

interface PositionSizerProps {
  fundAUM: number
  nav: number
  onSuggest?: (amount: number, units: number) => void
}

export function PositionSizer({ fundAUM, nav, onSuggest }: PositionSizerProps) {
  const [portfolioValue, setPortfolioValue] = useState<number>(fundAUM || 0)
  const [riskPercent, setRiskPercent] = useState<number>(1) // percent of portfolio risked per trade
  const [stopLossPercent, setStopLossPercent] = useState<number>(2) // expected stop loss percent

  useEffect(() => {
    setPortfolioValue(fundAUM || 0)
  }, [fundAUM])

  const suggested = useMemo(() => {
    // position size in amount = (portfolioValue * riskPercent/100) / (stopLossPercent/100)
    if (!stopLossPercent || stopLossPercent === 0) return { amount: 0, units: 0 }
    const amount = (portfolioValue * (riskPercent / 100)) / (stopLossPercent / 100)
    const units = nav > 0 ? amount / nav : 0
    return { amount, units }
  }, [portfolioValue, riskPercent, stopLossPercent, nav])

  return (
    <div className="rounded-lg border p-4">
      <h3 className="text-lg font-semibold mb-3">Position Sizer</h3>
      <div className="grid gap-3">
        <div>
          <label className="block text-sm text-gray-600">Portfolio Value (INR)</label>
          <Input type="number" value={portfolioValue || ""} onChange={(e: any) => setPortfolioValue(Number(e.target.value))} />
        </div>

        <div className="grid grid-cols-2 gap-3">
          <div>
            <label className="block text-sm text-gray-600">Risk per Trade (%)</label>
            <Input type="number" value={riskPercent} onChange={(e: any) => setRiskPercent(Number(e.target.value))} />
          </div>
          <div>
            <label className="block text-sm text-gray-600">Stop Loss (%)</label>
            <Input type="number" value={stopLossPercent} onChange={(e: any) => setStopLossPercent(Number(e.target.value))} />
          </div>
        </div>

        <div className="pt-2">
          <div className="text-sm text-gray-500">Suggested Position Size</div>
          <div className="text-lg font-semibold">₹{suggested.amount.toFixed(2)} ({suggested.units.toFixed(2)} units)</div>
        </div>

        <div className="flex justify-end">
          <Button onClick={() => onSuggest && onSuggest(suggested.amount, suggested.units)}>Use Suggestion</Button>
        </div>
      </div>
    </div>
  )
}
