"use client"

import { useEffect, useState } from "react"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { LocalDB } from "@/lib/local-storage/db"

export function FundTransactions({ fundId }: { fundId: string }) {
  const [txs, setTxs] = useState<any[]>([])

  useEffect(() => {
    let mounted = true
    const load = async () => {
      try {
        const all = await LocalDB.getAllTransactions()
        const filtered = (all || []).filter((t: any) => t.fund_id === fundId).sort((a: any, b: any) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime())
        if (!mounted) return
        setTxs(filtered)
      } catch (err) {
        console.error(err)
      }
    }

    load()
    return () => {
      mounted = false
    }
  }, [fundId])

  return (
    <Card>
      <CardHeader>
        <CardTitle>Recent Transactions</CardTitle>
      </CardHeader>
      <CardContent>
        {txs.length === 0 && <div className="text-sm text-gray-500">No recent transactions for this fund.</div>}
        <div className="space-y-2">
          {txs.map((t) => (
            <div key={t.id} className="flex items-center justify-between rounded-md border p-3">
              <div>
                <div className="text-sm font-medium">{t.transaction_type.toUpperCase()} — ₹{Number(t.amount).toFixed(2)}</div>
                <div className="text-xs text-gray-500">Units: {Number(t.units).toFixed(2)} — NAV: ₹{Number(t.nav).toFixed(2)}</div>
              </div>
              <div className="text-right text-xs text-gray-500">{new Date(t.created_at).toLocaleString()}</div>
            </div>
          ))}
        </div>
      </CardContent>
    </Card>
  )
}
